// ============================================================
// STEP 1 — EXTRACT ALL RAW SIGNALS FROM PAYLOAD
// ============================================================
const body = $input.first().json.body;
const jobAuth = body?.data?.['jobAuth-buyer']?.jobAuthDetails;
const companyBuyer = body?.data?.['companyBuyer']?.clientInfoByOpening;
const clientDetails = body?.data?.['client-details'] ?? [];
const companyDetails = body?.data?.['company-details'] ?? [];
const companyPage = body?.data?.['company-page']?.agencyStaffsAuth;

// ── Job info ────────────────────────────────────────────────
const job = jobAuth?.opening?.job ?? {};
const jobTitle = body?.jobTitle ?? job?.info?.title ?? 'N/A';
const jobDescription = job?.description ?? '';
const jobType = job?.info?.type ?? 'N/A';
const jobStatus = job?.status ?? 'N/A';
const jobCiphertext = body?.jobCiphertext ?? job?.info?.ciphertext ?? '';
const jobUrl = jobCiphertext ? `https://www.upwork.com/jobs/${jobCiphertext}` : 'N/A';
const engagement = job?.engagementDuration?.label ?? 'N/A';
const postedOn = job?.postedOn ?? 'N/A';
const contractorTier = job?.contractorTier ?? 'N/A';
const budget = job?.budget?.amount ?? null;
const budgetCurrency = job?.budget?.currencyCode ?? 'USD';
const hourlyMin = job?.extendedBudgetInfo?.hourlyBudgetMin ?? null;
const hourlyMax = job?.extendedBudgetInfo?.hourlyBudgetMax ?? null;
const skills = [
  ...(job?.sandsData?.ontologySkills ?? []),
  ...(job?.sandsData?.additionalSkills ?? [])
].map(s => s.prefLabel).filter(Boolean).join(', ');

// ── Client activity ─────────────────────────────────────────
const activity = companyBuyer?.activity ?? jobAuth?.opening?.job?.clientActivity ?? {};
const totalApplicants = activity?.totalApplicants ?? 0;
const totalHired = activity?.totalHired ?? 0;
const totalInvited = activity?.totalInvitedToInterview ?? 0;
const lastActivity = activity?.lastBuyerActivity ?? 'N/A';

// ── Buyer stats ─────────────────────────────────────────────
const buyer = jobAuth?.buyer ?? {};
const buyerInfo = buyer?.info ?? {};
const stats = buyerInfo?.stats ?? {};
const location = buyerInfo?.location ?? {};
const city = location?.city ?? 'N/A';
const country = location?.country ?? 'N/A';
const state = companyBuyer?.buyer?.info?.location?.state ?? '';
const isPaymentVerified = buyer?.isPaymentMethodVerified ?? companyBuyer?.buyer?.isPaymentMethodVerified ?? false;
const isEnterprise = buyer?.enterprise ?? companyBuyer?.buyer?.isEnterprise ?? false;
const totalSpent = stats?.totalCharges?.amount ?? companyBuyer?.buyer?.info?.stats?.totalCharges?.amount ?? 0;
const score = stats?.score ?? companyBuyer?.buyer?.info?.stats?.score ?? 0;
const feedbackCount = stats?.feedbackCount ?? 0;
const totalAssignments = stats?.totalAssignments ?? 0;
const activeAssignments = stats?.activeAssignmentsCount ?? 0;
const hoursCount = stats?.hoursCount ?? 0;
const totalJobsWithHires = stats?.totalJobsWithHires ?? 0;
const postedCount = buyerInfo?.jobs?.postedCount ?? companyBuyer?.buyer?.info?.jobs?.postedCount ?? 0;
const filledCount = companyBuyer?.buyer?.info?.jobs?.filledCount ?? 0;
const openCount = buyerInfo?.jobs?.openCount ?? 0;
const avgHourlyRate = buyerInfo?.avgHourlyJobsRate?.amount ?? 0;
const memberSince = buyerInfo?.company?.contractDate ?? companyBuyer?.buyer?.info?.company?.contractDate ?? 'N/A';

// ── Company direct fields ────────────────────────────────────
const apiCompanyName = buyerInfo?.company?.name ?? companyBuyer?.buyer?.info?.company?.name ?? null;
const companyLogo = buyerInfo?.logo ?? companyBuyer?.buyer?.info?.logo ?? null;
const companyIndustry = buyerInfo?.company?.profile?.industry ?? null;
const companySize = buyerInfo?.company?.profile?.size ?? null;

// ── Open jobs ────────────────────────────────────────────────
const openJobs = (buyerInfo?.jobs?.openJobs ?? []).map(j => j.title).filter(Boolean);

// ── Staff / team members from company-page ───────────────────
const staffs = (companyPage?.staffs ?? []).map(s => ({
  name: s.personalData?.name ?? 'Unknown',
  ciphertext: s.personalData?.ciphertext ?? '',
  profileUrl: s.personalData?.ciphertext ? `https://www.upwork.com/freelancers/${s.personalData.ciphertext}` : '',
  topRated: s.personalData?.topRatedStatus,
  memberType: s.memberType
}));

// ── Client details with agencies ─────────────────────────────
const clientsWithAgencies = clientDetails
  .filter(c => c.agencies && c.agencies.length > 0)
  .flatMap(c => c.agencies.map(a => ({
    clientName: c.name,
    agencyName: a.name ?? null,
    agencyLogo: a.logo ?? null,
    agencyUrl: a.url ?? null
  })));

// Agency company name & logo (first found)
const agencyCompanyName = clientsWithAgencies[0]?.agencyName ?? null;
const agencyCompanyLogo = clientsWithAgencies[0]?.agencyLogo ?? null;

// ── Primary client name (from staffs or client-details) ──────
const primaryClientName = staffs[0]?.name ?? clientDetails[0]?.name ?? 'Unknown';

// ── Work history ─────────────────────────────────────────────
const workHistory = buyer?.workHistory ?? [];
const workHistoryTitles = workHistory
  .map(w => w.jobInfo?.title)
  .filter(Boolean);

// Names mentioned in feedback (clients sometimes called by name)
const feedbackNames = workHistory
  .flatMap(w => [w.feedback?.comment, w.feedbackToClient?.comment])
  .filter(Boolean)
  .join(' ');

// Extract first-name mentions from feedback (e.g. "David is great")
const nameMatches = feedbackNames.match(/\b([A-Z][a-z]+)\b(?= is| was| has| did| always)/g) ?? [];
const extractedNamesFromFeedback = [...new Set(nameMatches)].slice(0, 3);

// ── Company name extraction from description ─────────────────
// Look for patterns like: "for XYZ", "XYZ (Company)", "at XYZ"
const descCompanyMatch = jobDescription.match(
  /(?:for|at|by|from|with)\s+([A-Z][A-Za-z0-9&.\-\s]{2,40})(?:\s*\(|\s*[\-–]|\.|,|$)/
);
const descExtractedCompany = descCompanyMatch?.[1]?.trim() ?? null;

// Also grab anything in parentheses after a company-like word
const parenMatch = jobDescription.match(/([A-Z][A-Za-z0-9]+)\s*\(([^)]{3,40})\)/);
const parenCompany = parenMatch ? `${parenMatch[1]} (${parenMatch[2]})` : null;

// ── Build final company name with priority chain ─────────────
const companyName =
  apiCompanyName ||
  agencyCompanyName ||
  descExtractedCompany ||
  parenCompany ||
  null; // AI will fill this if still null

// ── Build AI prompt ──────────────────────────────────────────
const aiPrompt = companyName ? null : `
Extract the company name from this Upwork job data.

JOB TITLE: ${jobTitle}

JOB DESCRIPTION (first 600 chars):
${jobDescription.slice(0, 600)}

OPEN JOBS:
${openJobs.slice(0, 4).join('\n')}

WORK HISTORY TITLES:
${workHistoryTitles.slice(0, 15).join('\n')}

NAMES FROM FEEDBACK: ${extractedNamesFromFeedback.join(', ')}

LOCATION: ${city}, ${country}

Respond ONLY with valid JSON, no markdown:
{"companyName": "...", "personName": "...", "confidence": "high|medium|low"}
`.trim();

return [{
  json: {
    // Job
    jobTitle,
    jobDescription,
    jobUrl,
    jobType,
    jobStatus,
    engagement,
    postedOn,
    contractorTier,
    budget,
    budgetCurrency,
    hourlyMin,
    hourlyMax,
    skills,
    // Client activity
    totalApplicants,
    totalHired,
    totalInvited,
    lastActivity,
    // Buyer
    city,
    country,
    state,
    isPaymentVerified,
    isEnterprise,
    totalSpent,
    score,
    feedbackCount,
    totalAssignments,
    activeAssignments,
    hoursCount,
    totalJobsWithHires,
    postedCount,
    filledCount,
    openCount,
    avgHourlyRate,
    memberSince,
    // Company
    companyName,
    companyLogo,
    companyIndustry,
    companySize,
    agencyCompanyName,
    agencyCompanyLogo,
    // People
    primaryClientName,
    staffs: JSON.stringify(staffs),
    clientsWithAgencies: JSON.stringify(clientsWithAgencies),
    extractedNamesFromFeedback: extractedNamesFromFeedback.join(', '),
    // Work history
    workHistoryTitles: workHistoryTitles.slice(0, 10).join(' | '),
    openJobs: openJobs.join(' | '),
    // AI
    aiPrompt,
    needsAI: !companyName
  }
}];

// Call Claude API to extract company name
const item = $input.first().json;

try {
  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 150,
      messages: [{ role: 'user', content: item.aiPrompt }]
    })
  });

  const data = await response.json();
  const raw = data.content?.[0]?.text ?? '{}';
  const parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());

  return [{
    json: {
      ...item,
      companyName: parsed.companyName || item.primaryClientName || 'Unknown',
      aiPersonName: parsed.personName || null,
      aiConfidence: parsed.confidence || 'low',
      source: 'ai'
    }
  }];
} catch (e) {
  return [{
    json: {
      ...item,
      companyName: item.primaryClientName || 'Unknown',
      aiConfidence: 'low',
      source: 'fallback'
    }
  }];
}

// Already has company name — just tag source
const item = $input.first().json;
return [{
  json: {
    ...item,
    source: item.agencyCompanyName ? 'agency' : 'api'
  }
}];

// ============================================================
// STEP 2 — BUILD QUALIFIED LEAD + FORMAT TELEGRAM MESSAGE
// ============================================================
const d = $input.first().json;

// Parse staffs back
let staffs = [];
try { staffs = JSON.parse(d.staffs || '[]'); } catch(e) {}

// ── Lead scoring ─────────────────────────────────────────────
let score = 0;
let scoreReasons = [];

if (d.isPaymentVerified) { score += 30; scoreReasons.push('✅ Payment verified'); }
if (d.totalSpent > 10000) { score += 20; scoreReasons.push(`💰 $${Math.round(d.totalSpent/1000)}K spent`); }
else if (d.totalSpent > 1000) { score += 10; scoreReasons.push(`💰 $${Math.round(d.totalSpent)} spent`); }
if (d.score >= 4.5) { score += 15; scoreReasons.push(`⭐ ${d.score} rating`); }
if (d.totalJobsWithHires > 5) { score += 10; scoreReasons.push(`🤝 ${d.totalJobsWithHires} jobs with hires`); }
if (d.totalApplicants < 30) { score += 10; scoreReasons.push(`🎯 Only ${d.totalApplicants} applicants`); }
if (d.budget > 500 || d.hourlyMax > 50) { score += 15; scoreReasons.push('💵 Good budget'); }

const leadGrade = score >= 70 ? '🔥 HOT' : score >= 45 ? '🟡 WARM' : '🔵 COLD';

// ── Format budget ────────────────────────────────────────────
let budgetStr = 'N/A';
if (d.hourlyMin && d.hourlyMax) {
  budgetStr = `$${d.hourlyMin}–$${d.hourlyMax}/hr`;
} else if (d.budget) {
  budgetStr = `$${d.budget} ${d.jobType === 'FIXED' ? 'fixed' : ''}`;
}

// ── Format total spent ───────────────────────────────────────
const spentStr = d.totalSpent >= 1000
  ? `$${(d.totalSpent / 1000).toFixed(1)}K`
  : `$${d.totalSpent}`;

// ── Staff lines ───────────────────────────────────────────────
const staffLines = staffs
  .map(s => {
    const badge = s.topRated === 'top_rated' ? ' ⭐' : '';
    return s.profileUrl
      ? `  👤 <a href="${s.profileUrl}">${s.name}</a>${badge}`
      : `  👤 ${s.name}${badge}`;
  })
  .join('\n') || '  No profiles found';

// ── Truncate description ─────────────────────────────────────
const desc = (d.jobDescription || '').slice(0, 500).trim() + (d.jobDescription?.length > 500 ? '...' : '');

// ── Company logo line ─────────────────────────────────────────
const logoLine = (d.companyLogo || d.agencyCompanyLogo)
  ? `🖼 <a href="${d.companyLogo || d.agencyCompanyLogo}">Company Logo</a>`
  : null;

// ── Build Telegram message ────────────────────────────────────
const lines = [
  `${leadGrade} <b>New Upwork Lead</b>`,
  ``,
  `📌 <b><a href="${d.jobUrl}">${d.jobTitle}</a></b>`,
  ``,
  `📝 ${desc}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `💼 <b>Job Details</b>`,
  `• <b>Type:</b> ${d.jobType}`,
  `• <b>Tier:</b> ${d.contractorTier}`,
  `• <b>Engagement:</b> ${d.engagement}`,
  `• <b>Budget:</b> ${budgetStr}`,
  `• <b>Skills:</b> ${d.skills || 'N/A'}`,
  `• <b>Posted:</b> ${new Date(d.postedOn).toLocaleDateString()}`,
  `• <b>Applicants:</b> ${d.totalApplicants} | Hired: ${d.totalHired} | Interviews: ${d.totalInvited}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `🏢 <b>Client Info</b>`,
  `• <b>Company:</b> ${d.companyName || 'Unknown'} <i>(${d.source})</i>`,
  logoLine,
  `• <b>Person:</b> ${d.aiPersonName || d.primaryClientName}`,
  `• <b>Industry:</b> ${d.companyIndustry || 'N/A'}`,
  `• <b>Size:</b> ${d.companySize ? d.companySize + ' employees' : 'N/A'}`,
  `• <b>Location:</b> ${d.city}, ${d.state ? d.state + ', ' : ''}${d.country}`,
  `• <b>Member since:</b> ${d.memberSince ? new Date(d.memberSince).getFullYear() : 'N/A'}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `📊 <b>Client History</b>`,
  `• <b>Total Spent:</b> ${spentStr}`,
  `• <b>Rating:</b> ${d.score}/5 (${d.feedbackCount} reviews)`,
  `• <b>Jobs Posted:</b> ${d.postedCount} | Filled: ${d.filledCount} | Open: ${d.openCount}`,
  `• <b>Active Contracts:</b> ${d.activeAssignments}`,
  `• <b>Hours Logged:</b> ${d.hoursCount}`,
  `• <b>Avg Hourly Rate Paid:</b> $${d.avgHourlyRate?.toFixed(2)}`,
  `• <b>Payment:</b> ${d.isPaymentVerified ? '✅ Verified' : '❌ Not verified'}`,
  `• <b>Enterprise:</b> ${d.isEnterprise ? '✅ Yes' : 'No'}`,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `👥 <b>Team Members</b>`,
  staffLines,
  ``,
  `━━━━━━━━━━━━━━━━━━`,
  `🏆 <b>Lead Score: ${score}/100 — ${leadGrade}</b>`,
  scoreReasons.join(' | '),
].filter(l => l !== null).join('\n');

// Trim to Telegram 4096 limit
const message = lines.length > 4096 ? lines.slice(0, 4090) + '...' : lines;

return [{
  json: {
    // Pass everything forward for Google Sheets
    ...d,
    leadScore: score,
    leadGrade,
    message,
    budgetFormatted: budgetStr,
    spentFormatted: spentStr,
    staffFormatted: staffs.map(s => s.name).join(', '),
    scoreReasons: scoreReasons.join(', ')
  }
}];

